document.addEventListener("DOMContentLoaded", function () {
  "use strict";

  // 1. Back to Top button visibility
  const backToTop = document.querySelector(".backtotop");
  window.addEventListener("scroll", function () {
    if (backToTop) {
      backToTop.style.display = window.scrollY > 200 ? "block" : "none";
    }
  });

  // 2. Smooth scroll to top when clicking the scroll button
  document.querySelectorAll(".scroll").forEach(function (btn) {
    btn.addEventListener("click", function (e) {
      e.preventDefault();
      window.scrollTo({ top: 0, behavior: "smooth" });
    });
  });

  // 3. Sticky header effect on scroll
  const header = document.querySelector(".site_header");
  window.addEventListener("scroll", function () {
    if (header) {
      header.classList.toggle("sticky", window.scrollY > 0);
    }
  });

  // 4. Toggle active state for pricing items
  const pricingBtn = document.querySelector(".pricing_toggle_btn");
  if (pricingBtn) {
    pricingBtn.addEventListener("click", function () {
      this.classList.toggle("active");
      document.querySelectorAll(".pricing_item").forEach(function (item) {
        item.classList.toggle("active");
      });
    });
  }

  // 5. Active Link Highlight (Scroll Spy & Click Event)
  const navLinks = document.querySelectorAll(".nav-link");
  const sections = document.querySelectorAll("section");

  // Update active class on scroll
  window.addEventListener("scroll", function () {
    let current = "";
    sections.forEach((section) => {
      const sectionTop = section.offsetTop - 150; // Offset for header height
      if (window.scrollY >= sectionTop) {
        current = section.getAttribute("id");
      }
    });

    navLinks.forEach((link) => {
      link.parentElement.classList.remove("active");
      // Ensure href exists and starts with # before comparing
      const href = link.getAttribute("href");
      if (href && href.startsWith("#") && href.substring(1) === current) {
        link.parentElement.classList.add("active");
      }
    });
  });

  // Handle click events for internal links vs external page links
  navLinks.forEach((link) => {
    link.addEventListener("click", function (e) {
      const href = this.getAttribute("href");

      // If the link is an internal anchor starting with #, perform smooth scroll
      if (href && href.startsWith("#")) {
        const targetElement = document.querySelector(href);
        if (targetElement) {
          e.preventDefault();
          targetElement.scrollIntoView({ behavior: "smooth" });

          navLinks.forEach((item) =>
            item.parentElement.classList.remove("active"),
          );
          this.parentElement.classList.add("active");
        }
      }
      // If the link is a standard page link (like index.html#home),
      // preventDefault is not called, allowing the browser to navigate normally.
    });
  });
});
